    if (!user) {
      return res.status(401).json({ error: 'Invalid session' });
    }
    res.json({ user });
  } catch {
    res.status(401).json({ error: 'Invalid or expired token' });
  }
});

module.exports = router;

const express = require('express');
const prisma = require('../lib/prisma');
const { authRequired } = require('../middleware/auth');

const router = express.Router();

const journalInclude = {
  user: { select: { id: true, username: true, avatar: true } },
  _count: { select: { likes: true, comments: true } },
};

router.get('/feed', async (_req, res) => {
  const journals = await prisma.journal.findMany({
    orderBy: { createdAt: 'desc' },
    take: 50,
    include: journalInclude,
  });
  res.json({ journals });
});

router.get('/:id', async (req, res) => {
  const id = Number(req.params.id);
  if (Number.isNaN(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const journal = await prisma.journal.findUnique({
    where: { id },
    include: {
      ...journalInclude,
      comments: {
        orderBy: { createdAt: 'asc' },
        include: { user: { select: { id: true, username: true, avatar: true } } },
      },
      likes: { select: { userId: true, type: true } },
    },
  });
  if (!journal) {
    return res.status(404).json({ error: 'Journal not found' });
  }
  res.json({ journal });
});

router.post('/', authRequired, async (req, res) => {
  const {
    title,
    destination,
    startDate,
    endDate,
    activities,
    accommodation,
    budget,
    photos,
    itinerary,
    content,
    tripId,
  } = req.body;

  if (!title || !destination || !startDate || !endDate) {
    return res.status(400).json({ error: 'title, destination, startDate, endDate are required' });
  }

  if (tripId != null) {
    const trip = await prisma.trip.findFirst({
      where: { id: Number(tripId), userId: req.user.id },
    });
    if (!trip) {
      return res.status(404).json({ error: 'Trip not found or not yours' });
    }
    const existing = await prisma.journal.findUnique({ where: { tripId: trip.id } });
    if (existing) {
      return res.status(409).json({ error: 'This trip already has a linked journal' });
    }
  }

  const journal = await prisma.journal.create({
    data: {
      userId: req.user.id,
      title,
      destination,
      startDate: new Date(startDate),
      endDate: new Date(endDate),
      activities: activities ?? null,
      accommodation: accommodation ?? null,
      budget: budget != null ? Number(budget) : null,
      photos: typeof photos === 'string' ? photos : JSON.stringify(photos ?? []),
      itinerary: typeof itinerary === 'string' ? itinerary : JSON.stringify(itinerary ?? []),
      content: content ?? null,
      tripId: tripId != null ? Number(tripId) : null,
    },
    include: journalInclude,
  });

  res.status(201).json({ journal });
});

