const express = require('express');
const prisma = require('../lib/prisma');
const { authRequired } = require('../middleware/auth');

const router = express.Router();

const tripInclude = {
  days: {
    orderBy: { dayIndex: 'asc' },
    include: { places: { orderBy: { sortOrder: 'asc' } } },
  },
  members: { include: { user: { select: { id: true, username: true, avatar: true } } } },
  budget: true,
  packing: { include: { items: { orderBy: { orderIndex: 'asc' } } } },
};

function canAccessTrip(trip, userId) {
  if (trip.userId === userId) {
    return true;
  }
  return trip.members.some((m) => m.userId === userId);
}

router.use(authRequired);

router.get('/', async (req, res) => {
  const trips = await prisma.trip.findMany({
    where: {
      OR: [{ userId: req.user.id }, { members: { some: { userId: req.user.id } } }],
    },
    orderBy: { updatedAt: 'desc' },
    include: {
      days: { select: { id: true, dayIndex: true, date: true, _count: { select: { places: true } } } },
      _count: { select: { members: true } },
    },
  });
  res.json({ trips });
});

router.post('/', async (req, res) => {
  const { title, description, startDate, endDate, days: dayPayload } = req.body;
  if (!title || !startDate || !endDate) {
    return res.status(400).json({ error: 'title, startDate, endDate are required' });
  }

  const trip = await prisma.$transaction(async (tx) => {
    const created = await tx.trip.create({
      data: {
        userId: req.user.id,
        title,
        description: description ?? null,
        startDate: new Date(startDate),
        endDate: new Date(endDate),
        members: {
          create: { userId: req.user.id, role: 'owner' },
        },
      },
    });

    if (Array.isArray(dayPayload) && dayPayload.length > 0) {
      for (const d of dayPayload) {
        const day = await tx.tripDay.create({
          data: {
            tripId: created.id,
            dayIndex: Number(d.dayIndex),
            date: new Date(d.date),
            notes: d.notes ?? null,
          },
        });
        const places = Array.isArray(d.places) ? d.places : [];
        let order = 0;
        for (const p of places) {
          await tx.tripPlace.create({
            data: {
              tripDayId: day.id,
              name: p.name,
              lat: p.lat != null ? Number(p.lat) : null,
              lng: p.lng != null ? Number(p.lng) : null,
              category: p.category ?? null,
              notes: p.notes ?? null,
              sortOrder: p.sortOrder != null ? Number(p.sortOrder) : order++,
            },
          });
        }
      }
    }

    return tx.trip.findUnique({
      where: { id: created.id },
      include: tripInclude,
    });
  });

  res.status(201).json({ trip });
});

router.get('/:id', async (req, res) => {
  const id = Number(req.params.id);
  if (Number.isNaN(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const trip = await prisma.trip.findUnique({
    where: { id },
    include: tripInclude,
  });
  if (!trip) {
    return res.status(404).json({ error: 'Trip not found' });
  }
  if (!canAccessTrip(trip, req.user.id)) {
    return res.status(403).json({ error: 'Forbidden' });
  }
  res.json({ trip });
});

router.patch('/:id', async (req, res) => {
  const id = Number(req.params.id);
  if (Number.isNaN(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const trip = await prisma.trip.findUnique({
    where: { id },
    include: { members: true },
  });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }

  const { title, description, startDate, endDate } = req.body;
  const updated = await prisma.trip.update({
    where: { id },
    data: {
      ...(title != null ? { title } : {}),
      ...(description !== undefined ? { description } : {}),
      ...(startDate != null ? { startDate: new Date(startDate) } : {}),
      ...(endDate != null ? { endDate: new Date(endDate) } : {}),
    },
    include: tripInclude,
  });
  res.json({ trip: updated });
});

/** Replace all days & places (TREK-style planner save) */
router.put('/:id/plan', async (req, res) => {
  const id = Number(req.params.id);
  if (Number.isNaN(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const trip = await prisma.trip.findUnique({
    where: { id },
    include: { members: true },
  });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }

  const { days: dayPayload } = req.body;
  if (!Array.isArray(dayPayload)) {
    return res.status(400).json({ error: 'days array required' });
  }

  await prisma.$transaction(async (tx) => {
    await tx.tripPlace.deleteMany({
      where: { day: { tripId: id } },
    });
    await tx.tripDay.deleteMany({ where: { tripId: id } });

    for (const d of dayPayload) {
      const day = await tx.tripDay.create({
        data: {
          tripId: id,
          dayIndex: Number(d.dayIndex),
          date: new Date(d.date),
          notes: d.notes ?? null,
        },
      });
      const places = Array.isArray(d.places) ? d.places : [];
      let order = 0;
      for (const p of places) {
        await tx.tripPlace.create({
          data: {
            tripDayId: day.id,
            name: p.name,
            lat: p.lat != null ? Number(p.lat) : null,
            lng: p.lng != null ? Number(p.lng) : null,
            category: p.category ?? null,
            notes: p.notes ?? null,
            sortOrder: p.sortOrder != null ? Number(p.sortOrder) : order++,
          },
        });
      }
    }
  });

  const fresh = await prisma.trip.findUnique({
    where: { id },
    include: tripInclude,
  });
  res.json({ trip: fresh });
});

router.post('/:id/budget', async (req, res) => {
  const id = Number(req.params.id);
  const { title, amount, category, notes, date } = req.body;
  if (Number.isNaN(id) || !title || amount == null) {
    return res.status(400).json({ error: 'title and amount required' });
  }
  const trip = await prisma.trip.findUnique({ where: { id }, include: { members: true } });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }
  const line = await prisma.tripBudgetLine.create({
    data: {
      tripId: id,
      userId: req.user.id,
      title,
      amount: Number(amount),
      category: category ?? 'other',
      notes: notes ?? null,
      date: date ? new Date(date) : new Date(),
    },
  });
  res.status(201).json({ line });
});

router.get('/:id/budget', async (req, res) => {
  const id = Number(req.params.id);
  if (Number.isNaN(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const trip = await prisma.trip.findUnique({ where: { id }, include: { members: true } });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }
  const lines = await prisma.tripBudgetLine.findMany({
    where: { tripId: id },
    orderBy: { date: 'desc' },
  });
  res.json({ lines });
});

router.post('/:id/packing/lists', async (req, res) => {
  const id = Number(req.params.id);
  const { name } = req.body;
  if (Number.isNaN(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const trip = await prisma.trip.findUnique({ where: { id }, include: { members: true } });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }
  const list = await prisma.tripPackingList.create({
    data: { tripId: id, name: name || 'Packing' },
    include: { items: true },
  });
  res.status(201).json({ list });
});

router.post('/:id/packing/lists/:listId/items', async (req, res) => {
  const id = Number(req.params.id);
  const listId = Number(req.params.listId);
  const { name, category, quantity, notes } = req.body;
  if (Number.isNaN(id) || Number.isNaN(listId) || !name) {
    return res.status(400).json({ error: 'name required' });
  }
  const trip = await prisma.trip.findUnique({ where: { id }, include: { members: true } });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }
  const list = await prisma.tripPackingList.findFirst({ where: { id: listId, tripId: id } });
  if (!list) {
    return res.status(404).json({ error: 'List not found' });
  }
  const maxOrder = await prisma.tripPackingItem.aggregate({
    where: { packingListId: listId },
    _max: { orderIndex: true },
  });
  const item = await prisma.tripPackingItem.create({
    data: {
      packingListId: listId,
      name,
      category: category ?? 'general',
      quantity: quantity != null ? Number(quantity) : 1,
      notes: notes ?? null,
      orderIndex: (maxOrder._max.orderIndex ?? -1) + 1,
    },
  });
  res.status(201).json({ item });
});

router.patch('/:id/packing/items/:itemId', async (req, res) => {
  const id = Number(req.params.id);
  const itemId = Number(req.params.itemId);
  const { packed } = req.body;
  const trip = await prisma.trip.findUnique({ where: { id }, include: { members: true } });
  if (!trip || !canAccessTrip(trip, req.user.id)) {
    return res.status(trip ? 403 : 404).json({ error: trip ? 'Forbidden' : 'Trip not found' });
  }
  const item = await prisma.tripPackingItem.findFirst({
    where: { id: itemId, list: { tripId: id } },
  });
  if (!item) {
    return res.status(404).json({ error: 'Item not found' });
  }
  const updated = await prisma.tripPackingItem.update({
    where: { id: itemId },
    data: { ...(typeof packed === 'boolean' ? { packed } : {}) },
  });
  res.json({ item: updated });
});

module.exports = router;

const express = require('express');
const prisma = require('../lib/prisma');
const { authRequired } = require('../middleware/auth');

const router = express.Router();

router.get('/users/search', async (req, res) => {
  const q = (req.query.q || '').trim();
  if (q.length < 2) {
    return res.json({ users: [] });
  }
  const users = await prisma.user.findMany({
    where: {
      OR: [
        { username: { contains: q, mode: 'insensitive' } },
        { email: { contains: q, mode: 'insensitive' } },
      ],
    },
    take: 20,
    select: { id: true, username: true, avatar: true, bio: true },
  });
  res.json({ users });
});

router.post('/follow/:userId', authRequired, async (req, res) => {
  const followingId = Number(req.params.userId);
  if (Number.isNaN(followingId) || followingId === req.user.id) {
    return res.status(400).json({ error: 'Invalid user' });
  }
  await prisma.follow.upsert({
    where: {
      followerId_followingId: { followerId: req.user.id, followingId },
    },
    create: { followerId: req.user.id, followingId },
    update: {},
  });
  res.json({ ok: true });
});

router.delete('/follow/:userId', authRequired, async (req, res) => {
  const followingId = Number(req.params.userId);
  if (Number.isNaN(followingId)) {
    return res.status(400).json({ error: 'Invalid user' });
  }
  await prisma.follow.deleteMany({
    where: { followerId: req.user.id, followingId },
  });
  res.json({ ok: true });
});

module.exports = router;

