  return (
    <div className="max-w-md mx-auto">
      <h1 className="text-2xl font-semibold mb-2">
        {mode === 'login' ? 'Welcome back' : 'Create account'}
      </h1>
      <p className="text-slate-400 text-sm mb-6">
        Fusion combines Roamera-style journals with a TREK-inspired day-by-day planner.
      </p>
      <form onSubmit={onSubmit} className="space-y-4 bg-slate-900 border border-slate-800 rounded-xl p-6">
        {mode === 'register' && (
          <div>
            <label className="block text-xs uppercase tracking-wide text-slate-500 mb-1">Username</label>
            <input
              className="w-full rounded-lg bg-slate-950 border border-slate-700 px-3 py-2"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              autoComplete="username"
            />
          </div>
        )}
        <div>
          <label className="block text-xs uppercase tracking-wide text-slate-500 mb-1">Email</label>
          <input
            type="email"
            className="w-full rounded-lg bg-slate-950 border border-slate-700 px-3 py-2"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            autoComplete="email"
          />
        </div>
        <div>
          <label className="block text-xs uppercase tracking-wide text-slate-500 mb-1">Password</label>
          <input
            type="password"
            className="w-full rounded-lg bg-slate-950 border border-slate-700 px-3 py-2"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            autoComplete={mode === 'login' ? 'current-password' : 'new-password'}
          />
        </div>
        {error && <p className="text-rose-400 text-sm">{error}</p>}
        <button
          type="submit"
          disabled={busy}
          className="w-full py-2 rounded-lg bg-teal-600 hover:bg-teal-500 disabled:opacity-50 font-medium"
        >
          {busy ? 'Please wait…' : mode === 'login' ? 'Log in' : 'Register'}
        </button>
      </form>
      <p className="text-center text-sm text-slate-500 mt-4">
        {mode === 'login' ? (
          <>
            No account?{' '}
            <button type="button" className="text-teal-400" onClick={() => setMode('register')}>
              Register
            </button>
          </>
        ) : (
          <>
            Have an account?{' '}
            <button type="button" className="text-teal-400" onClick={() => setMode('login')}>
              Log in
            </button>
          </>
        )}
        {' · '}
        <Link to="/" className="text-slate-400 hover:text-white">
          Back to feed
        </Link>
      </p>
    </div>
  );
}

