import { useEffect, useState } from 'react';
import client from '../api/client';

function defaultDays(start, end) {
  const s = new Date(start);
  const e = new Date(end);
  const days = [];
  for (let d = new Date(s), i = 0; d <= e; d.setDate(d.getDate() + 1), i++) {
    days.push({
      dayIndex: i,
      date: d.toISOString().slice(0, 10),
      notes: '',
      places: [],
    });
  }
  return days;
}

export default function TripPlannerPage() {
  const [trips, setTrips] = useState([]);
  const [selectedId, setSelectedId] = useState(null);
  const [trip, setTrip] = useState(null);
  const [newTitle, setNewTitle] = useState('My trip');
  const [startDate, setStartDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [endDate, setEndDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [placeForms, setPlaceForms] = useState({});
  const [budgetTitle, setBudgetTitle] = useState('');
  const [budgetAmount, setBudgetAmount] = useState('');
  const [packName, setPackName] = useState('');
  const [error, setError] = useState('');

  async function refreshList() {
    const { data } = await client.get('/trips');
    setTrips(data.trips);
  }

  useEffect(() => {
    refreshList().catch(() => setError('Could not load trips'));
  }, []);

  useEffect(() => {
    if (!selectedId) {
      setTrip(null);
      return;
    }
    client
      .get(`/trips/${selectedId}`)
      .then((r) => setTrip(r.data.trip))
      .catch(() => setError('Could not load trip'));
  }, [selectedId]);

  async function createTrip(e) {
    e.preventDefault();
    setError('');
    try {
      const days = defaultDays(startDate, endDate);
      const { data } = await client.post('/trips', {
        title: newTitle,
        startDate,
        endDate,
        days,
      });
      await refreshList();
      setSelectedId(data.trip.id);
    } catch (err) {
      setError(err.response?.data?.error || 'Create failed');
    }
  }

  function updatePlaceForm(dayId, field, value) {
    setPlaceForms((prev) => ({
      ...prev,
      [dayId]: { ...prev[dayId], [field]: value },
    }));
  }

  async function addPlace(day) {
    const form = placeForms[day.id] || {};
    const name = (form.name || '').trim();
    if (!name) {
      return;
    }
    const lat = form.lat ? Number(form.lat) : null;
    const lng = form.lng ? Number(form.lng) : null;
    const nextDays = trip.days.map((d) => {
      if (d.id !== day.id) {
        return d;
      }
      const places = [
        ...d.places,
        {
          name,
          lat,
          lng,
          category: form.category || 'sight',
          notes: form.notes || '',
          sortOrder: d.places.length,
        },
      ];
      return { ...d, places };
    });
    try {
      const { data } = await client.put(`/trips/${trip.id}/plan`, { days: serializeDays(nextDays) });
      setTrip(data.trip);
      updatePlaceForm(day.id, 'name', '');
      updatePlaceForm(day.id, 'lat', '');
      updatePlaceForm(day.id, 'lng', '');
    } catch (err) {
      setError(err.response?.data?.error || 'Save failed');
    }
  }

  function serializeDays(days) {
    return days.map((d) => ({
      dayIndex: d.dayIndex,
      date: typeof d.date === 'string' ? d.date : new Date(d.date).toISOString(),
      notes: d.notes || '',
      places: (d.places || []).map((p, i) => ({
        name: p.name,
        lat: p.lat,
        lng: p.lng,
        category: p.category,
        notes: p.notes,
        sortOrder: p.sortOrder ?? i,
      })),
    }));
  }

  async function addBudget(e) {
    e.preventDefault();
    if (!trip || !budgetTitle || !budgetAmount) {
      return;
    }
    try {
      await client.post(`/trips/${trip.id}/budget`, {
        title: budgetTitle,
        amount: Number(budgetAmount),
      });
      setBudgetTitle('');
      setBudgetAmount('');
      const { data } = await client.get(`/trips/${trip.id}`);
      setTrip(data.trip);
    } catch (err) {
      setError(err.response?.data?.error || 'Budget add failed');
    }
  }

  async function ensurePackingAndAddItem(e) {
    e.preventDefault();
    if (!trip || !packName.trim()) {
      return;
    }
    try {
      let listId = trip.packing?.[0]?.id;
      if (!listId) {
        const r = await client.post(`/trips/${trip.id}/packing/lists`, { name: 'Main' });
        listId = r.data.list.id;
      }
      await client.post(`/trips/${trip.id}/packing/lists/${listId}/items`, { name: packName.trim() });
      setPackName('');
      const { data } = await client.get(`/trips/${trip.id}`);
      setTrip(data.trip);
    } catch (err) {
      setError(err.response?.data?.error || 'Packing failed');
    }
  }

  async function togglePacked(item) {
    try {
      await client.patch(`/trips/${trip.id}/packing/items/${item.id}`, { packed: !item.packed });
      const { data } = await client.get(`/trips/${trip.id}`);
      setTrip(data.trip);
    } catch {
      setError('Update failed');
    }
  }

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-3xl font-bold">Trip planner</h1>
        <p className="text-slate-400 mt-1">
          Day-by-day places with coordinates (ready for a map layer), budget lines, and packing — same conceptual
          model as TREK, unified with Roamera accounts.
        </p>
      </div>

      {error && <p className="text-rose-400 text-sm">{error}</p>}

      <section className="grid md:grid-cols-2 gap-8">
        <div>
          <h2 className="font-semibold mb-3">Your trips</h2>
          <ul className="space-y-2 mb-6">
            {trips.map((t) => (
              <li key={t.id}>
                <button
                  type="button"
                  onClick={() => setSelectedId(t.id)}
                  className={`w-full text-left px-4 py-3 rounded-lg border text-sm ${
                    selectedId === t.id
                      ? 'border-teal-500 bg-teal-950/40'
                      : 'border-slate-800 bg-slate-900/40 hover:border-slate-600'
                  }`}
                >
                  <div className="font-medium text-white">{t.title}</div>
                  <div className="text-slate-500 text-xs">
                    {t.days.length} days · {t._count.members} members
                  </div>
                </button>
              </li>
            ))}
          </ul>
          <form onSubmit={createTrip} className="space-y-3 bg-slate-900/50 border border-slate-800 rounded-xl p-4">
            <h3 className="text-sm font-medium text-slate-300">New trip</h3>
            <input
              className="w-full rounded-lg bg-slate-950 border border-slate-700 px-3 py-2 text-sm"
              value={newTitle}
              onChange={(e) => setNewTitle(e.target.value)}
              placeholder="Title"
            />
            <div className="flex gap-2">
              <input
                type="date"
                className="flex-1 rounded-lg bg-slate-950 border border-slate-700 px-3 py-2 text-sm"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
              <input
                type="date"
                className="flex-1 rounded-lg bg-slate-950 border border-slate-700 px-3 py-2 text-sm"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
            <button type="submit" className="w-full py-2 rounded-lg bg-teal-600 hover:bg-teal-500 text-sm font-medium">
              Create & generate days
            </button>
          </form>
        </div>

        <div>
          {!trip ? (
            <p className="text-slate-500 text-sm">Select or create a trip.</p>
          ) : (
            <div className="space-y-6">
              <div>
                <h2 className="font-semibold text-white">{trip.title}</h2>
                <p className="text-slate-500 text-xs">
                  {new Date(trip.startDate).toLocaleDateString()} — {new Date(trip.endDate).toLocaleDateString()}
                </p>
              </div>

              <div className="space-y-4 max-h-[420px] overflow-y-auto pr-1">
                {trip.days.map((day) => (
                  <div key={day.id} className="border border-slate-800 rounded-xl p-4 bg-slate-900/30">
                    <div className="text-sm font-medium text-teal-400">
                      Day {day.dayIndex + 1} · {new Date(day.date).toLocaleDateString()}
                    </div>
                    <ul className="mt-2 space-y-1 text-sm text-slate-300">
