                          )}
                        </li>
                      ))}
                    </ul>
                    <div className="mt-3 grid grid-cols-2 gap-2">
                      <input
                        className="rounded bg-slate-950 border border-slate-700 px-2 py-1 text-xs col-span-2"
                        placeholder="Place name"
                        value={placeForms[day.id]?.name || ''}
                        onChange={(e) => updatePlaceForm(day.id, 'name', e.target.value)}
