                          className={`mr-2 ${item.packed ? 'text-teal-400' : 'text-slate-500'}`}
                          onClick={() => togglePacked(item)}
                        >
                          {item.packed ? '☑' : '☐'}
                        </button>
                        {item.name}
                      </li>
                    )),
                  )}
                </ul>
              </div>
            </div>
          )}
        </div>
      </section>
    </div>
  );
